(() => {
  const allElements = document.querySelectorAll('h3, div, span, p');
  for (let el of allElements) {
    const text = el.textContent.trim();
    if (/^(Counter|1|2|3|0)$/.test(text)) {
      return { tag: el.tagName, text: text, className: el.className, parentText: el.parentElement?.textContent?.trim()?.substring(0, 100) };
    }
  }
  return null;
})()

(() => {
  const elements = [...document.querySelectorAll('*')];
  const counterElements = elements.filter(el => el.textContent.includes('Counter'));
  return counterElements.map(el => ({
    tag: el.tagName,
    text: el.textContent.trim(),
    id: el.id,
    className: el.className
  }));
})()

(() => {
  const addBtn = [...document.querySelectorAll('button')].find(b => b.textContent.trim() === 'Add');
  const todoInput = addBtn?.parentElement?.querySelector('input');
  return {
    addBtn: addBtn ? { tag: addBtn.tagName, text: addBtn.textContent.trim() } : null,
    todoInput: todoInput ? { tag: todoInput.tagName, id: todoInput.id, className: todoInput.className, placeholder: todoInput.placeholder } : null
  };
})()

(() => {
  const btn = [...document.querySelectorAll('button')].find(b => b.textContent.trim() === 'Add');
  if (!btn) return null;
  return btn.parentElement.outerHTML.substring(0, 500);
})()
